import numpy as np

class Layer:
    def __init__(self, input_size, output_size, activation=None):
        self.weights = np.random.randn(input_size, output_size) * np.sqrt(2. / input_size)
        self.biases = np.zeros((1, output_size))
        self.activation = activation
        self.input = None
        self.output = None
        self.dweights = None
        self.dbiases = None
        self.dinput = None

    def forward(self, input):
        self.input = input
        self.output = np.dot(input, self.weights) + self.biases

        if self.activation == 'relu':
            self.output = np.maximum(0, self.output)
        elif self.activation == 'sigmoid':
            self.output = 1 / (1 + np.exp(-self.output))
        elif self.activation == 'tanh':
            self.output = np.tanh(self.output)

        return self.output

    def backward(self, doutput):
        if self.activation == 'relu':
            doutput = doutput * (self.output > 0)
        elif self.activation == 'sigmoid':
            doutput = doutput * (self.output * (1 - self.output))
        elif self.activation == 'tanh':
            doutput = doutput * (1 - self.output ** 2)

        self.dweights = np.dot(self.input.T, doutput)
        self.dbiases = np.sum(doutput, axis=0, keepdims=True)
        self.dinput = np.dot(doutput, self.weights.T)
        return self.dinput

class NeuralNetwork:
    def __init__(self):
        self.layers = []

    def add_layer(self, layer):
        self.layers.append(layer)

    def forward(self, X):
        for layer in self.layers:
            X = layer.forward(X)
        return X

    def backward(self, doutput):
        for layer in reversed(self.layers):
            doutput = layer.backward(doutput)

    def update_params(self, learning_rate):
        for layer in self.layers:
            layer.weights -= learning_rate * layer.dweights
            layer.biases -= learning_rate * layer.dbiases

def mse_loss(y_true, y_pred):
    return np.mean((y_true - y_pred) ** 2)

def mse_loss_grad(y_true, y_pred):
    return 2 * (y_pred - y_true) / y_true.size

def cross_entropy_loss(y_true, y_pred):
    epsilon = 1e-15
    y_pred = np.clip(y_pred, epsilon, 1 - epsilon)
    return -np.mean(y_true * np.log(y_pred) + (1 - y_true) * np.log(1 - y_pred))

def cross_entropy_loss_grad(y_true, y_pred):
    epsilon = 1e-15
    y_pred = np.clip(y_pred, epsilon, 1 - epsilon)
    return (y_pred - y_true) / (y_pred * (1 - y_pred))

def train_regression(network, X, y, epochs=1000, learning_rate=0.01):
    for epoch in range(epochs):
        y_pred = network.forward(X)
        loss = mse_loss(y, y_pred)
        grad = mse_loss_grad(y, y_pred)
        network.backward(grad)
        network.update_params(learning_rate)

        if epoch % 100 == 0:
            print(f"Epoch {epoch}, Loss: {loss}")

def train_classification(network, X, y, epochs=1000, learning_rate=0.01):
    for epoch in range(epochs):
        y_pred = network.forward(X)
        loss = cross_entropy_loss(y, y_pred)
        grad = cross_entropy_loss_grad(y, y_pred)
        network.backward(grad)
        network.update_params(learning_rate)

        if epoch % 100 == 0:
            print(f"Epoch {epoch}, Loss: {loss}")

