X_reg = np.array([[0, 0], [0, 1], [1, 0], [1, 1]])
y_reg = np.array([[0], [1], [1], [0]])

nn_reg = NeuralNetwork()
nn_reg.add_layer(Layer(2, 4, 'relu'))
nn_reg.add_layer(Layer(4, 1))

print("Training regression model...")
train_regression(nn_reg, X_reg, y_reg)

