import numpy as np

class NeuralNetwork:
    def __init__(self, layer_sizes, activation='relu', output_activation='linear'):
        self.layer_sizes = layer_sizes
        self.activation = activation
        self.output_activation = output_activation
        self.weights = []
        self.biases = []

        for i in range(len(layer_sizes) - 1):
            self.weights.append(np.random.randn(layer_sizes[i], layer_sizes[i+1]) * np.sqrt(2. / layer_sizes[i]))
            self.biases.append(np.zeros((1, layer_sizes[i+1])))

    def _activate(self, x, activation_type):
        if activation_type == 'relu':
            return np.maximum(0, x)
        elif activation_type == 'sigmoid':
            return 1 / (1 + np.exp(-x))
        elif activation_type == 'tanh':
            return np.tanh(x)
        elif activation_type == 'linear':
            return x
        else:
            raise ValueError("Unsupported activation function")

    def _activate_derivative(self, x, activation_type):
        if activation_type == 'relu':
            return (x > 0).astype(float)
        elif activation_type == 'sigmoid':
            s = self._activate(x, 'sigmoid')
            return s * (1 - s)
        elif activation_type == 'tanh':
            return 1 - np.tanh(x)**2
        elif activation_type == 'linear':
            return np.ones_like(x)
        else:
            raise ValueError("Unsupported activation function")

    def forward(self, X):
        self.layer_outputs = [X]
        for i in range(len(self.weights)):
            z = np.dot(self.layer_outputs[-1], self.weights[i]) + self.biases[i]
            if i == len(self.weights) - 1:
                a = self._activate(z, self.output_activation)
            else:
                a = self._activate(z, self.activation)
            self.layer_outputs.append(a)
        return self.layer_outputs[-1]

    def backward(self, X, y, learning_rate):
        m = X.shape[0]
        output_error = self.layer_outputs[-1] - y

        for i in reversed(range(len(self.weights))):
            if i == len(self.weights) - 1:
                delta = output_error * self._activate_derivative(self.layer_outputs[i+1], self.output_activation)
            else:
                delta = np.dot(delta, self.weights[i+1].T) * self._activate_derivative(self.layer_outputs[i+1], self.activation)

            dW = np.dot(self.layer_outputs[i].T, delta) / m
            db = np.sum(delta, axis=0, keepdims=True) / m

            self.weights[i] -= learning_rate * dW
            self.biases[i] -= learning_rate * db

    def train(self, X, y, epochs, learning_rate, batch_size=None, verbose=True):
        if batch_size is None:
            batch_size = X.shape[0]

        for epoch in range(epochs):
            indices = np.random.permutation(X.shape[0])
            X_shuffled = X[indices]
            y_shuffled = y[indices]

            for i in range(0, X.shape[0], batch_size):
                X_batch = X_shuffled[i:i+batch_size]
                y_batch = y_shuffled[i:i+batch_size]

                self.forward(X_batch)
                self.backward(X_batch, y_batch, learning_rate)

            if verbose and epoch % 100 == 0:
                predictions = self.forward(X)
                if self.output_activation == 'sigmoid':
                    loss = -np.mean(y * np.log(predictions + 1e-8) + (1 - y) * np.log(1 - predictions + 1e-8))
                else:
                    loss = np.mean((predictions - y)**2)
                print(f"Epoch {epoch}, Loss: {loss:.4f}")

# Regression example
def regression_example():
    np.random.seed(42)
    X = np.random.rand(1000, 5)
    y = np.sin(X.sum(axis=1)).reshape(-1, 1)

    nn = NeuralNetwork(layer_sizes=[5, 64, 32, 1], activation='relu', output_activation='linear')
    nn.train(X, y, epochs=1000, learning_rate=0.01, batch_size=32)

    test_X = np.random.rand(10, 5)
    predictions = nn.forward(test_X)
    print("\nRegression predictions:")
    print(predictions)

# Classification example
def classification_example():
    np.random.seed(42)
    X = np.random.randn(1000, 10)
    y = (X.sum(axis=1) > 0).astype(int).reshape(-1, 1)

    nn = NeuralNetwork(layer_sizes=[10, 64, 32, 1], activation='relu', output_activation='sigmoid')
    nn.train(X, y, epochs=1000, learning_rate=0.01, batch_size=32)

    test_X = np.random.randn(10, 10)
    predictions = nn.forward(test_X)
    print("\nClassification predictions (probabilities):")
    print(predictions)

if __name__ == "__main__":
    print("Running regression example...")
    regression_example()

    print("\nRunning classification example...")
    classification_example()
